messages.content:
{
  "intent": "check_and_fix",
  "intent_description": "R2 Serial0/1/0 is administratively down, causing the R1<->R2 serial link to be down and OSPF adjacency loss. Restore the physical/link connectivity by enabling R2 Serial0/1/0 so the interface reaches oper up and OSPF neighbors return.",
  "target": null,
  "needs_fix": true,
  "plan": {
    "problem": "R2 Serial0/1/0 is administratively shutdown, causing the link to R1 to be down and OSPF neighbor loss.",
    "fix_summary": "Bring R2 Serial0/1/0 admin state to up (no shutdown) to restore the link and OSPF adjacency.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/0",
        "parameters": [
          "admin_state=up"
        ]
      }
    ]
  }
}
